#include <vector>
#include <string>
#include <algorithm>
#include <regex>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<string> validCoupons;
    vector<pair<int, string>> categorizedCoupons;

    // Define the order of business lines
    vector<string> businessOrder = {"electronics", "grocery", "pharmacy", "restaurant"};

    // Regex for valid code: only alphanumeric and underscore
    regex codePattern("^[a-zA-Z0-9_]+$");

    for (size_t i = 0; i < code.size(); ++i) {
        // Check if the coupon is valid
        if (!isActive[i]) continue;
        if (code[i].empty()) continue;
        if (!regex_match(code[i], codePattern)) continue;

        // Check if businessLine is valid
        auto it = find(businessOrder.begin(), businessOrder.end(), businessLine[i]);
        if (it == businessOrder.end()) continue;

        // Get the priority of the business line
        int priority = distance(businessOrder.begin(), it);
        categorizedCoupons.emplace_back(priority, code[i]);
    }

    // Sort the coupons first by business line priority, then by code
    sort(categorizedCoupons.begin(), categorizedCoupons.end(), 
        [](const pair<int, string>& a, const pair<int, string>& b) {
            if (a.first != b.first) {
                return a.first < b.first;
            } else {
                return a.second < b.second;
            }
        });

    // Extract the sorted codes
    for (const auto& coupon : categorizedCoupons) {
        validCoupons.push_back(coupon.second);
    }

    return validCoupons;
}

