function solve(code, businessLine, isActive) {
    const validCoupons = [];
    const businessOrder = ["electronics", "grocery", "pharmacy", "restaurant"];

    for (let i = 0; i < code.length; i++) {
        if (!isActive[i]) continue;
        if (!code[i] || code[i].length === 0) continue;
        if (!/^[a-zA-Z0-9_]+$/.test(code[i])) continue;

        const business = businessLine[i];
        if (!businessOrder.includes(business)) continue;

        validCoupons.push({
            priority: businessOrder.indexOf(business),
            code: code[i]
        });
    }

    validCoupons.sort((a, b) => {
        if (a.priority !== b.priority) {
            return a.priority - b.priority;
        } else {
            return a.code.localeCompare(b.code);
        }
    });

    return validCoupons.map(coupon => coupon.code);
}
